const token = $env.SIDE_BRAIN_CAPTURE_TOKEN;
const headers = $json.headers || {};
const auth = headers.authorization || headers.Authorization || '';
const body = $json.body || {};
const content = String(body.content ?? '').trim();
const type = String(body.type || 'capture').trim();
const source = String(body.source || 'iphone-shortcut').trim();
const allowedTypes = ['capture', 'task', 'idea', 'question'];

let ok = true;
let statusCode = 200;
let error = '';

if (!token) {
  ok = false;
  statusCode = 500;
  error = 'SIDE_BRAIN_CAPTURE_TOKEN is not configured in n8n.';
} else if (auth !== `Bearer ${token}`) {
  ok = false;
  statusCode = 401;
  error = 'Unauthorized';
} else if (!content) {
  ok = false;
  statusCode = 400;
  error = 'content cannot be empty';
} else if (!allowedTypes.includes(type)) {
  ok = false;
  statusCode = 400;
  error = `type must be one of: ${allowedTypes.join(', ')}`;
}

const requestId = `${Date.now()}-${Math.random().toString(36).slice(2)}`;
const payload = { content, type, source };

return [{
  json: {
    ok,
    statusCode,
    error,
    requestId,
    payloadBase64: Buffer.from(JSON.stringify(payload), 'utf8').toString('base64')
  }
}];
